package com.example.integration;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;
import org.xml.sax.InputSource;

import javax.jws.WebService;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import java.io.StringReader;
import java.io.IOException;

// Service Implementation
@WebService(endpointInterface = "com.example.integration.IDataIntegrationService")
public class DataIntegrationServiceImpl implements IDataIntegrationService {

    @Override
    public String processXmlDocument(String xmlPayload) {
        // Log the received payload (truncated for large payloads for readability)
        System.out.println("Received XML payload:\n" + xmlPayload.substring(0, Math.min(xmlPayload.length(), 500)) + (xmlPayload.length() > 500 ? "..." : ""));

        try {
            // Configure DocumentBuilderFactory for security and handling large XML
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

            // Secure XML parsing to prevent XXE (XML External Entity) attacks and similar vulnerabilities.
            // These features prevent the parser from processing external entities, DTDs, and XInclude.
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            // factory.setExpandEntityReferences(false); // This feature might not be available in all Java versions or parsers,
                                                       // but if present, it also helps with security/memory.

            // IMPORTANT NOTE ON LARGE XML PAYLOADS:
            // DocumentBuilder creates an in-memory DOM (Document Object Model) tree of the entire XML document.
            // For truly "large" XML documents (e.g., hundreds of MBs or GBs with deeply nested structures),
            // this can quickly lead to OutOfMemoryError as it consumes a significant amount of heap memory.
            // If actual large payloads cause memory issues in production, consider alternative parsing strategies:
            // 1. Using a streaming parser like SAX (Simple API for XML) or StAX (Streaming API for XML)
            //    for better memory efficiency. These parsers process the XML document sequentially
            //    without loading the entire structure into memory. This would require changing the
            //    parsing and processing logic from DOM traversal to an event-based or cursor-based approach.
            // 2. Breaking down very large XML files into smaller, manageable chunks on the client side
            //    before sending them to the service.
            // 3. Increasing JVM heap size (a temporary workaround, not a scalable solution for very large files).
            // This implementation strictly adheres to the explicit requirement of using DocumentBuilder.
            DocumentBuilder builder = factory.newDocumentBuilder();

            // Parse the XML string into a Document object
            Document document = builder.parse(new InputSource(new StringReader(xmlPayload)));
            // Normalize the document: puts all text nodes in the full depth of the given subtrees underneath their containing element nodes.
            // This is useful for consistent text node handling.
            document.getDocumentElement().normalize();

            System.out.println("Root element of parsed XML: " + document.getDocumentElement().getNodeName());

            // --- Example of processing complex XML structure with nested entities ---
            // This logic demonstrates traversing the DOM tree to extract data.
            NodeList itemNodes = document.getElementsByTagName("Item");
            StringBuilder processingSummary = new StringBuilder();
            processingSummary.append("Processing summary for ").append(itemNodes.getLength()).append(" items:\n");

            for (int i = 0; i < itemNodes.getLength(); i++) {
                Node itemNode = itemNodes.item(i);
                if (itemNode.getNodeType() == Node.ELEMENT_NODE) {
                    Element itemElement = (Element) itemNode;
                    String itemId = itemElement.getAttribute("id");
                    String itemName = getElementTextContent(itemElement, "Name");
                    String itemDescription = getElementTextContent(itemElement, "Description");

                    processingSummary.append("  Item ID: ").append(itemId)
                                       .append(", Name: ").append(itemName)
                                       .append(", Description (partial): ").append(itemDescription.substring(0, Math.min(itemDescription.length(), 50)))
                                       .append("\n");

                    // Process nested <Attributes>
                    NodeList attributeNodes = itemElement.getElementsByTagName("Attribute");
                    for (int j = 0; j < attributeNodes.getLength(); j++) {
                        Node attributeNode = attributeNodes.item(j);
                        if (attributeNode.getNodeType() == Node.ELEMENT_NODE) {
                            Element attributeElement = (Element) attributeNode;
                            String attrName = attributeElement.getAttribute("name");
                            String attrValue = attributeElement.getTextContent();
                            processingSummary.append("    Attribute: ").append(attrName).append(" = ").append(attrValue).append("\n");
                        }
                    }

                    // Process nested <NestedElement> with <SubNestedElement>
                    NodeList nestedElementNodes = itemElement.getElementsByTagName("NestedElement");
                    if (nestedElementNodes.getLength() > 0) {
                        Element nestedElement = (Element) nestedElementNodes.item(0); // Assuming one NestedElement per Item
                        NodeList subNestedNodes = nestedElement.getElementsByTagName("SubNestedElement");
                        for (int k = 0; k < subNestedNodes.getLength(); k++) {
                            Node subNestedNode = subNestedNodes.item(k);
                            if (subNestedNode.getNodeType() == Node.ELEMENT_NODE) {
                                Element subNestedElement = (Element) subNestedNode;
                                String key = subNestedElement.getAttribute("key");
                                String value = subNestedElement.getTextContent();
                                processingSummary.append("    Nested: ").append(key).append(" = ").append(value).append("\n");
                            }
                        }
                    }
                }
            }

            System.out.println(processingSummary.toString());

            // Construct a simple XML response
            return "<Response><Status>Success</Status><Message>XML document processed successfully. " + itemNodes.getLength() + " items found.</Message></Response>";

        } catch (ParserConfigurationException e) {
            System.err.println("Error configuring XML parser: " + e.getMessage());
            return "<Response><Status>Error</Status><Message>Parser configuration error: " + escapeXml(e.getMessage()) + "</Message></Response>";
        } catch (IOException e) {
            System.err.println("IO Error parsing XML: " + e.getMessage());
            return "<Response><Status>Error</Status><Message>IO Error parsing XML: " + escapeXml(e.getMessage()) + "</Message></Response>";
        } catch (org.xml.sax.SAXException e) {
            System.err.println("SAX Error parsing XML: " + e.getMessage());
            return "<Response><Status>Error</Status><Message>XML parsing error: " + escapeXml(e.getMessage()) + "</Message></Response>";
        } catch (Exception e) {
            // Catch any other unexpected exceptions
            System.err.println("An unexpected error occurred during XML processing: " + e.getMessage());
            e.printStackTrace(); // Print stack trace for debugging
            return "<Response><Status>Error</Status><Message>An unexpected server error occurred: " + escapeXml(e.getMessage()) + "</Message></Response>";
        }
    }

    /**
     * Helper method to get the text content of the first element with a given tag name
     * within a parent element.
     * @param parentElement The parent XML element.
     * @param tagName The tag name of the child element.
     * @return The text content of the child element, or an empty string if not found.
     */
    private String getElementTextContent(Element parentElement, String tagName) {
        NodeList nodeList = parentElement.getElementsByTagName(tagName);
        if (nodeList != null && nodeList.getLength() > 0) {
            // getTextContent() concatenates all text nodes within the element.
            return nodeList.item(0).getTextContent();
        }
        return "";
    }

    /**
     * Helper method to escape XML special characters for inclusion in response messages,
     * preventing potential XML parsing errors or injection.
     * @param text The string to escape.
     * @return The escaped string.
     */
    private String escapeXml(String text) {
        return text.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&apos;");
    }
}
package com.example.integration;

import javax.xml.ws.Endpoint;

// Endpoint Publisher
public class DataIntegrationServicePublisher {

    public static void main(String[] args) {
        String url = "http://localhost:8080/DataIntegrationService";
        System.out.println("Publishing Data Integration Service at: " + url);

        // Publish the service implementation.
        // The service will be available at the specified URL.
        Endpoint.publish(url, new DataIntegrationServiceImpl());

        System.out.println("Service published. WSDL available at: " + url + "?wsdl");
        System.out.println("Press Ctrl+C to stop the service.");

        // Keep the main thread alive indefinitely to keep the service running.
        // In a real enterprise environment, this service would typically be deployed
        // in an application server (like Tomcat, JBoss, WebSphere, etc.),
        // which manages the lifecycle of the endpoint, making this explicit sleep unnecessary.
        try {
            Thread.sleep(Long.MAX_VALUE);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            System.out.println("Service publisher interrupted. Shutting down.");
        }
    }
}
